<!DOCTYPE html>
<html lang="fr">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Sama Santé – Consultation en ligne</title>
<link href="https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700&family=Poppins:wght@600;700;800&display=swap" rel="stylesheet">
<style>
  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
  
  :root {
    --blue: #1A6FD8;
    --blue-dark: #1558B0;
    --blue-light: #EBF2FD;
    --orange: #F97316;
    --orange-light: #FEF3E8;
    --green: #16A34A;
    --gray-50: #F8FAFC;
    --gray-100: #F1F5F9;
    --gray-200: #E2E8F0;
    --gray-400: #94A3B8;
    --gray-600: #475569;
    --gray-700: #334155;
    --gray-900: #0F172A;
    --white: #FFFFFF;
    --radius: 12px;
    --shadow: 0 1px 3px rgba(0,0,0,.08), 0 4px 16px rgba(0,0,0,.06);
    --shadow-lg: 0 8px 32px rgba(0,0,0,.12);
  }

  body { font-family: 'Inter', sans-serif; color: var(--gray-900); background: var(--white); }

  /* NAV */
  nav {
    display: flex; align-items: center; justify-content: space-between;
    padding: 0 40px; height: 60px;
    background: var(--white); border-bottom: 1px solid var(--gray-200);
    position: sticky; top: 0; z-index: 100;
  }
  .nav-logo { display: flex; align-items: center; gap: 8px; font-family: 'Poppins', sans-serif; font-weight: 700; font-size: 18px; color: var(--blue); }
  .nav-logo-icon { width: 32px; height: 32px; background: var(--blue); border-radius: 8px; display: flex; align-items: center; justify-content: center; }
  .nav-logo-icon svg { fill: white; width: 18px; height: 18px; }
  .nav-links { display: flex; gap: 28px; list-style: none; }
  .nav-links a { font-size: 14px; color: var(--gray-600); text-decoration: none; transition: color .2s; }
  .nav-links a:hover, .nav-links a.active { color: var(--blue); font-weight: 500; }
  .nav-actions { display: flex; align-items: center; gap: 12px; }
  .nav-search { border: 1px solid var(--gray-200); border-radius: 8px; padding: 6px 12px; font-size: 13px; color: var(--gray-400); width: 180px; outline: none; }
  .nav-icons { display: flex; gap: 8px; }
  .icon-btn { width: 36px; height: 36px; border-radius: 50%; border: 1px solid var(--gray-200); background: var(--white); display: flex; align-items: center; justify-content: center; cursor: pointer; color: var(--gray-600); font-size: 16px; }

  /* HERO */
  .hero {
    position: relative; min-height: 420px;
    background: url("data:image/png;base64,") center right / cover no-repeat;
    display: flex; align-items: center; overflow: hidden;
  }
  .hero::before {
    content: '';
    position: absolute; inset: 0; z-index: 1;
    background: linear-gradient(90deg, rgba(10,46,107,0.92) 0%, rgba(26,111,216,0.80) 50%, rgba(26,111,216,0.20) 100%);
  }
  .hero-content { position: relative; z-index: 2; padding: 60px 40px; max-width: 560px; }
  .hero h1 { font-family: 'Poppins', sans-serif; font-size: 36px; font-weight: 800; color: white; line-height: 1.2; margin-bottom: 16px; }
  .hero h1 span { color: #60C0F8; }
  .hero p { font-size: 15px; color: rgba(255,255,255,.85); line-height: 1.6; margin-bottom: 28px; max-width: 420px; }
  .btn-primary { display: inline-flex; align-items: center; gap: 8px; background: var(--white); color: var(--blue); padding: 13px 28px; border-radius: 50px; font-weight: 600; font-size: 15px; text-decoration: none; box-shadow: 0 4px 20px rgba(0,0,0,.2); transition: transform .2s, box-shadow .2s; cursor: pointer; border: none; }
  .btn-primary:hover { transform: translateY(-2px); box-shadow: 0 8px 28px rgba(0,0,0,.25); }
  .hero-img { position: absolute; right: 0; top: 0; height: 100%; width: 55%; object-fit: cover; opacity: .45; }
  .hero-blob { position: absolute; right: 80px; top: 20px; width: 380px; height: 380px; border-radius: 50% 30% 50% 30%; background: rgba(255,255,255,.08); }

  /* SECTION WRAPPER */
  .section { padding: 56px 40px; }
  .section-title { text-align: center; font-family: 'Poppins', sans-serif; font-size: 22px; font-weight: 700; color: var(--gray-900); margin-bottom: 8px; }
  .section-sub { text-align: center; font-size: 14px; color: var(--gray-600); margin-bottom: 40px; max-width: 600px; margin-left: auto; margin-right: auto; }

  /* BOOKING FORM */
  .booking-section { background: var(--white); padding: 56px 40px; }
  .booking-steps { display: flex; align-items: center; justify-content: center; gap: 0; margin-bottom: 40px; }
  .step { display: flex; flex-direction: column; align-items: center; gap: 6px; }
  .step-num { width: 32px; height: 32px; border-radius: 50%; display: flex; align-items: center; justify-content: center; font-size: 13px; font-weight: 600; }
  .step.active .step-num { background: var(--blue); color: white; }
  .step.done .step-num { background: var(--green); color: white; }
  .step.inactive .step-num { background: var(--gray-200); color: var(--gray-600); }
  .step-label { font-size: 11px; color: var(--gray-600); white-space: nowrap; }
  .step-line { width: 80px; height: 2px; background: var(--gray-200); margin-bottom: 18px; }
  .step-line.done { background: var(--green); }

  .booking-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 32px; max-width: 900px; margin: 0 auto; }

  /* Form left */
  .form-group { margin-bottom: 20px; }
  .form-label { font-size: 13px; font-weight: 500; color: var(--gray-700); margin-bottom: 6px; display: block; }
  .form-select, .form-input { width: 100%; padding: 10px 14px; border: 1px solid var(--gray-200); border-radius: 8px; font-size: 14px; color: var(--gray-900); outline: none; transition: border .2s; background: var(--white); }
  .form-select:focus, .form-input:focus { border-color: var(--blue); box-shadow: 0 0 0 3px rgba(26,111,216,.12); }

  .doctor-card { display: flex; align-items: center; gap: 12px; padding: 12px 14px; border: 2px solid var(--gray-200); border-radius: 10px; cursor: pointer; margin-bottom: 10px; transition: all .2s; }
  .doctor-card.selected { border-color: var(--blue); background: var(--blue-light); }
  .doctor-card:hover { border-color: var(--blue); }
  .doctor-avatar { width: 44px; height: 44px; border-radius: 50%; background: var(--gray-200); display: flex; align-items: center; justify-content: center; font-size: 18px; overflow: hidden; }
  .doctor-info h4 { font-size: 14px; font-weight: 600; }
  .doctor-info p { font-size: 12px; color: var(--gray-400); }
  .doctor-info .rating { font-size: 12px; color: var(--orange); }

  /* Calendar grid */
  .calendar-label { font-size: 13px; font-weight: 500; color: var(--gray-700); margin-bottom: 10px; }
  .cal-grid { display: grid; grid-template-columns: repeat(7, 1fr); gap: 4px; margin-bottom: 20px; }
  .cal-day-header { font-size: 11px; color: var(--gray-400); text-align: center; padding: 4px; font-weight: 500; }
  .cal-day { font-size: 13px; text-align: center; padding: 8px 4px; border-radius: 8px; cursor: pointer; transition: all .2s; }
  .cal-day:hover { background: var(--blue-light); color: var(--blue); }
  .cal-day.selected { background: var(--blue); color: white; font-weight: 600; }
  .cal-day.inactive { color: var(--gray-200); cursor: default; }
  .time-grid { display: grid; grid-template-columns: repeat(3, 1fr); gap: 8px; }
  .time-slot { padding: 8px; border: 1px solid var(--gray-200); border-radius: 8px; text-align: center; font-size: 13px; cursor: pointer; transition: all .2s; }
  .time-slot:hover { border-color: var(--blue); color: var(--blue); }
  .time-slot.selected { background: var(--blue); color: white; border-color: var(--blue); }
  .time-slot.unavailable { color: var(--gray-300); cursor: not-allowed; text-decoration: line-through; }

  /* PAYMENT */
  .payment-section { background: var(--gray-50); padding: 48px 40px; }
  .payment-grid { display: grid; grid-template-columns: 1fr 320px; gap: 32px; max-width: 900px; margin: 0 auto; }
  .payment-methods { display: flex; gap: 16px; flex-wrap: wrap; margin-bottom: 16px; }
  .payment-method { display: flex; align-items: center; gap: 10px; padding: 14px 20px; border: 2px solid var(--gray-200); border-radius: 10px; cursor: pointer; transition: all .2s; background: white; }
  .payment-method.selected { border-color: var(--blue); background: var(--blue-light); }
  .payment-method label { font-size: 14px; font-weight: 500; cursor: pointer; }
  .payment-icon { width: 32px; height: 32px; border-radius: 6px; display: flex; align-items: center; justify-content: center; font-size: 18px; }
  .payment-note { font-size: 12px; color: var(--gray-400); margin-top: 10px; }
  .order-summary { background: white; border-radius: var(--radius); padding: 24px; box-shadow: var(--shadow); }
  .order-summary h3 { font-size: 15px; font-weight: 600; margin-bottom: 20px; }
  .order-row { display: flex; justify-content: space-between; align-items: center; padding: 8px 0; border-bottom: 1px solid var(--gray-100); font-size: 14px; }
  .order-row:last-of-type { border-bottom: none; }
  .order-row.total { font-weight: 700; font-size: 16px; color: var(--blue); border-top: 2px solid var(--gray-200); padding-top: 12px; margin-top: 4px; }
  .btn-pay { width: 100%; margin-top: 16px; background: var(--blue); color: white; border: none; padding: 14px; border-radius: 10px; font-size: 15px; font-weight: 600; cursor: pointer; transition: background .2s; display: flex; align-items: center; justify-content: center; gap: 8px; }
  .btn-pay:hover { background: var(--blue-dark); }

  /* QUEUE TRACKER */
  .queue-section { background: var(--white); padding: 56px 40px; }
  .queue-grid { display: grid; grid-template-columns: 280px 1fr; gap: 40px; max-width: 900px; margin: 0 auto; align-items: start; }
  .ticket-card { background: linear-gradient(135deg, #1A6FD8, #0A2E6B); color: white; border-radius: var(--radius); padding: 24px; text-align: center; }
  .ticket-header { font-size: 11px; letter-spacing: .08em; text-transform: uppercase; opacity: .8; margin-bottom: 8px; }
  .ticket-service { font-size: 13px; font-weight: 600; margin-bottom: 20px; }
  .ticket-qr { background: white; border-radius: 8px; width: 100px; height: 100px; margin: 0 auto 20px; display: grid; grid-template-columns: repeat(5,1fr); gap: 4px; padding: 12px; }
  .qr-cell { background: #0A2E6B; border-radius: 1px; }
  .qr-cell.white { background: white; }
  .ticket-num { font-family: 'Poppins', sans-serif; font-size: 26px; font-weight: 800; letter-spacing: .05em; }
  .ticket-meta { display: flex; justify-content: space-between; margin-top: 16px; font-size: 12px; opacity: .8; }

  .queue-stats { display: grid; grid-template-columns: 1fr 1fr; gap: 20px; margin-bottom: 24px; }
  .stat-card { background: var(--gray-50); border-radius: var(--radius); padding: 20px; text-align: center; }
  .stat-icon { font-size: 24px; margin-bottom: 8px; }
  .stat-num { font-family: 'Poppins', sans-serif; font-size: 32px; font-weight: 800; color: var(--blue); }
  .stat-label { font-size: 12px; color: var(--gray-600); }
  .progress-bar { background: var(--gray-200); border-radius: 50px; height: 8px; margin-bottom: 8px; overflow: hidden; }
  .progress-fill { height: 100%; border-radius: 50px; background: linear-gradient(90deg, var(--blue), #60C0F8); transition: width .5s; }
  .progress-labels { display: flex; justify-content: space-between; font-size: 12px; color: var(--gray-400); margin-bottom: 24px; }
  .queue-actions { display: flex; gap: 12px; }
  .btn-outline { flex: 1; padding: 10px; border: 1px solid var(--gray-200); border-radius: 8px; background: white; font-size: 13px; font-weight: 500; cursor: pointer; display: flex; align-items: center; justify-content: center; gap: 6px; transition: all .2s; }
  .btn-outline:hover { border-color: var(--blue); color: var(--blue); }

  /* WHY SECTION */
  .why-section { background: var(--gray-50); padding: 56px 40px; }
  .why-grid { display: grid; grid-template-columns: repeat(4, 1fr); gap: 24px; max-width: 960px; margin: 0 auto; }
  .why-card { background: white; border-radius: var(--radius); padding: 28px 20px; text-align: center; box-shadow: var(--shadow); transition: transform .2s; }
  .why-card:hover { transform: translateY(-4px); }
  .why-icon { width: 56px; height: 56px; border-radius: 16px; margin: 0 auto 16px; display: flex; align-items: center; justify-content: center; font-size: 26px; }
  .why-card h3 { font-size: 15px; font-weight: 600; margin-bottom: 8px; }
  .why-card p { font-size: 13px; color: var(--gray-600); line-height: 1.5; }

  /* TESTIMONIALS */
  .testimonials-section { background: white; padding: 56px 40px; }
  .testimonials-grid { display: grid; grid-template-columns: repeat(3, 1fr); gap: 24px; max-width: 960px; margin: 0 auto; }
  .testimonial-card { background: var(--gray-50); border-radius: var(--radius); padding: 24px; }
  .stars { color: #FBBF24; font-size: 14px; margin-bottom: 12px; }
  .testimonial-text { font-size: 14px; color: var(--gray-700); line-height: 1.6; margin-bottom: 16px; font-style: italic; }
  .testimonial-author { display: flex; align-items: center; gap: 10px; }
  .author-avatar { width: 40px; height: 40px; border-radius: 50%; background: linear-gradient(135deg, var(--blue), var(--blue-dark)); display: flex; align-items: center; justify-content: center; color: white; font-weight: 600; font-size: 14px; }
  .author-name { font-size: 14px; font-weight: 600; }
  .author-title { font-size: 12px; color: var(--gray-400); }
  .testimonials-nav { display: flex; justify-content: center; gap: 8px; margin-top: 32px; }
  .nav-dot { width: 8px; height: 8px; border-radius: 50%; background: var(--gray-200); cursor: pointer; }
  .nav-dot.active { background: var(--blue); width: 24px; border-radius: 4px; }

  /* FOOTER */
  footer { background: #0A2E6B; color: rgba(255,255,255,.8); padding: 48px 40px 32px; }
  .footer-grid { display: grid; grid-template-columns: 2fr 1fr 1fr 1fr; gap: 40px; max-width: 960px; margin: 0 auto 40px; }
  .footer-brand .nav-logo { color: white; margin-bottom: 12px; }
  .footer-brand p { font-size: 13px; line-height: 1.6; opacity: .7; }
  .footer-col h4 { font-size: 13px; font-weight: 600; color: white; margin-bottom: 16px; }
  .footer-col ul { list-style: none; }
  .footer-col li { margin-bottom: 10px; }
  .footer-col a { font-size: 13px; color: rgba(255,255,255,.7); text-decoration: none; transition: color .2s; }
  .footer-col a:hover { color: white; }
  .footer-contact p { font-size: 13px; margin-bottom: 8px; opacity: .7; }
  .footer-socials { display: flex; gap: 10px; margin-top: 16px; }
  .social-btn { width: 36px; height: 36px; border-radius: 50%; background: rgba(255,255,255,.15); display: flex; align-items: center; justify-content: center; font-size: 16px; cursor: pointer; transition: background .2s; }
  .social-btn:hover { background: rgba(255,255,255,.3); }
  .footer-bottom { border-top: 1px solid rgba(255,255,255,.15); padding-top: 20px; text-align: center; font-size: 12px; opacity: .5; max-width: 960px; margin: 0 auto; }
</style>
</head>
<body>

<!-- NAV -->
<nav>
  <div class="nav-logo">
    <div class="nav-logo-icon">
      <svg viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg"><path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm-1 14H9V8h2v8zm4 0h-2V8h2v8z"/><path d="M11 8h2v3h3v2h-3v3h-2v-3H8v-2h3z"/></svg>
    </div>
    Sama Santé
  </div>
  <ul class="nav-links">
    <li><a href="#" class="active"> Rendez-vous </a></li>
    
  </ul>
  <div class="nav-actions">
    <input class="nav-search" type="text" placeholder="Rechercher...">
    <div class="nav-icons">
      <button class="icon-btn">🔔</button>
      <button class="icon-btn">👤</button>
    </div>
  </div>
</nav>

<!-- HERO -->
<section class="hero">
  <div class="hero-blob"></div>
  <div class="hero-content">
    <h1>Réservez votre consultation<br><span>en quelques minutes</span></h1>
    <p>Choisissez votre service, payez en ligne via Wave ou Orange Money et suivez votre position dans la file d'attente en temps réel.</p>
    <button class="btn-primary">
      <span>En Savoir plus</span>
      <span>→</span>
    </button>
  </div>
</section>

<!-- BOOKING -->
<section class="booking-section">
  <h2 class="section-title">Finalisez votre réservation</h2>

  <div class="booking-steps">
    <div class="step done">
      <div class="step-num">✓</div>
      <div class="step-label">Service</div>
    </div>
    <div class="step-line done"></div>
    <div class="step active">
      <div class="step-num">2</div>
      <div class="step-label">Médecin</div>
    </div>
    <div class="step-line"></div>
    <div class="step inactive">
      <div class="step-num">3</div>
      <div class="step-label">Paiement</div>
    </div>
    <div class="step-line"></div>
    <div class="step inactive">
      <div class="step-num">4</div>
      <div class="step-label">Ticket</div>
    </div>
  </div>

  <div class="booking-grid">
    <!-- Left -->
    <div>
      <div class="form-group">
        <label class="form-label">Quel service souhaitez-vous ?</label>
        <select class="form-select">
          <option>Sélectionner</option>
          <option>Médecine Générale</option>
          <option>Pédiatrie</option>
          <option>Cardiologie</option>
        </select>
      </div>

      <div class="form-group">
        <label class="form-label">Choisissez votre médecin</label>
        <div class="doctor-card selected">
          <div class="doctor-avatar">👨‍⚕️</div>
          <div class="doctor-info">
            <h4>Dr. Mamadou Sy</h4>
            <p>Médecin Généraliste · 12 ans</p>
            <div class="rating">★★★★★ 4.9</div>
          </div>
        </div>
        <div class="doctor-card">
          <div class="doctor-avatar">👩‍⚕️</div>
          <div class="doctor-info">
            <h4>Dr. Aissatou Fall</h4>
            <p>Pédiatre · 8 ans</p>
            <div class="rating">★★★★☆ 4.7</div>
          </div>
        </div>
      </div>

      <div class="form-group" style="display:grid;grid-template-columns:1fr 1fr;gap:12px;">
        <div>
          <label class="form-label">Nom complet</label>
          <input class="form-input" type="text" placeholder="Prénom Nom">
        </div>
        <div>
          <label class="form-label">Numéro de téléphone</label>
          <input class="form-input" type="tel" placeholder="+221 7X XXX XX XX">
        </div>
      </div>
      <div class="form-group">
        <label class="form-label">Motif de la consultation (optionnel)</label>
        <input class="form-input" type="text" placeholder="Décrivez brièvement...">
      </div>
    </div>

    <!-- Right: Calendar -->
    <div>
      <div class="calendar-label">Sélectionnez une date</div>
      <div class="cal-grid">
        <div class="cal-day-header">L</div><div class="cal-day-header">M</div>
        <div class="cal-day-header">M</div><div class="cal-day-header">J</div>
        <div class="cal-day-header">V</div><div class="cal-day-header">S</div>
        <div class="cal-day-header">D</div>
        <div class="cal-day inactive">29</div><div class="cal-day inactive">30</div>
        <div class="cal-day">1</div><div class="cal-day">2</div>
        <div class="cal-day">3</div><div class="cal-day">4</div><div class="cal-day inactive">5</div>
        <div class="cal-day">6</div><div class="cal-day">7</div>
        <div class="cal-day">8</div><div class="cal-day">9</div>
        <div class="cal-day">10</div><div class="cal-day">11</div><div class="cal-day inactive">12</div>
        <div class="cal-day">13</div><div class="cal-day">14</div>
        <div class="cal-day">15</div><div class="cal-day selected">16</div>
        <div class="cal-day">17</div><div class="cal-day">18</div><div class="cal-day inactive">19</div>
        <div class="cal-day">20</div><div class="cal-day">21</div>
        <div class="cal-day">22</div><div class="cal-day">23</div>
        <div class="cal-day">24</div><div class="cal-day">25</div><div class="cal-day inactive">26</div>
      </div>

      <div class="calendar-label" style="margin-top:16px;">Choisissez un créneau</div>
      <div class="time-grid">
        <div class="time-slot">09:00</div>
        <div class="time-slot selected">09:30</div>
        <div class="time-slot">10:00</div>
        <div class="time-slot unavailable">10:30</div>
        <div class="time-slot">11:00</div>
        <div class="time-slot">11:30</div>
        <div class="time-slot unavailable">14:00</div>
        <div class="time-slot">14:30</div>
        <div class="time-slot">15:00</div>
      </div>
    </div>
  </div>
</section>

<!-- PAYMENT -->
<section class="payment-section">
  <h2 class="section-title">Méthode de paiement</h2>

  <div class="payment-grid">
    <div>
      <div class="payment-methods">
        <div class="payment-method selected">
          <div class="payment-icon" style="background:#E8F4FD;">💳</div>
          <input type="radio" name="pay" checked>
          <label>Wave</label>
        </div>
        <div class="payment-method">
          <div class="payment-icon" style="background:#FEF3E8;">🟠</div>
          <input type="radio" name="pay">
          <label>Orange Money</label>
        </div>
      </div>
      <p class="payment-note">✓ Paiement 100% sécurisé et crypté. Certifié CNDP.</p>
    </div>

    <div class="order-summary">
      <h3>Résumé</h3>
      <div class="order-row"><span>Consultation</span><span>10 000 FCFA</span></div>
      <div class="order-row"><span>Frais de service</span><span>500 FCFA</span></div>
      <div class="order-row total"><span>Total</span><span>10 500 FCFA</span></div>
      <button class="btn-pay">
        <span>💳</span>
        <span>Payer maintenant</span>
        <span>→</span>
      </button>
    </div>
  </div>
</section>

<!-- QUEUE TRACKER -->
<section class="queue-section">
