<script>
  // Calendar interaction
  document.querySelectorAll('.cal-day:not(.inactive)').forEach(d => {
    d.addEventListener('click', () => {
      document.querySelectorAll('.cal-day').forEach(x => x.classList.remove('selected'));
      d.classList.add('selected');
    });
  });

  // Time slots
  document.querySelectorAll('.time-slot:not(.unavailable)').forEach(s => {
    s.addEventListener('click', () => {
      document.querySelectorAll('.time-slot').forEach(x => x.classList.remove('selected'));
      s.classList.add('selected');
    });
  });

  // Payment methods
  document.querySelectorAll('.payment-method').forEach(m => {
    m.addEventListener('click', () => {
      document.querySelectorAll('.payment-method').forEach(x => x.classList.remove('selected'));
      m.classList.add('selected');
    });
  });

  // Doctor selection
  document.querySelectorAll('.doctor-card').forEach(c => {
    c.addEventListener('click', () => {
      document.querySelectorAll('.doctor-card').forEach(x => x.classList.remove('selected'));
      c.classList.add('selected');
    });
  });

  // Testimonials dots
  document.querySelectorAll('.nav-dot').forEach((dot, i) => {
    dot.addEventListener('click', () => {
      document.querySelectorAll('.nav-dot').forEach(d => d.classList.remove('active'));
      dot.classList.add('active');
    });
  });

  // Animate queue position
  let pos = 12;
  setInterval(() => {
    if (pos > 1) {
      pos--;
      document.querySelector('.queue-stats .stat-num') && (document.querySelectorAll('.stat-num')[0].textContent = '#' + pos);
    }
  }, 8000);
</script>
